import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import FlightPath from "../components/FlightPath";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const [position, setPosition] = useState([12.9716, 77.5946]);

  const path = [
    [12.9716, 77.5946],
    [15.2993, 74.124],
    [19.076, 72.8777],
  ];

  useEffect(() => {
    let lat = 12.9716;
    let lng = 77.5946;

    const interval = setInterval(() => {
      lat += 0.05;
      lng += 0.05;
      setPosition([lat, lng]);
    }, 300);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="dashboard">
      <div className="panel">✈️ Flight Tracker Live</div>

      <MapContainer center={position} zoom={5} className="map">
        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} />
        <FlightPath path={path} />
      </MapContainer>
    </div>
  );
}
